public record CodeChunk
{
	public required CodeItemKind Kind { get; init; }
	public required string Name { get; init; }
	public required int StartLineNumber { get; init; }
	public required int EndLineNumber { get; init; }
	public required string Text { get; init; }

	public int LineCount => EndLineNumber - StartLineNumber + 1;
}

public record CodeItem
{
    public required CodeItemKind Kind { get; init; }
    public required string Name { get; init; }
    public required int LineNumber { get; init; }
    public required int EndLineNumber { get; init; }
    public required string Signature { get; init; }

    public int LineCount => EndLineNumber - LineNumber + 1;
}

public record FileIndexEntry
{
    public required string FullPath { get; init; }
    public required string RelativePath { get; init; }
    public required string Extension { get; init; }
    public required long SizeBytes { get; init; }
    public required int LineCount { get; init; }
    public required int NonEmptyLineCount { get; init; }
    public required List<CodeItem> CodeItems { get; init; }
    public required List<CodeChunk> CodeChunks { get; init; }
    public required string? ErrorMessage { get; init; }

    public int CodeItemCount => CodeItems.Count;
    public int CodeChunkCount => CodeChunks.Count;
    public bool IsReadSuccessfully => ErrorMessage is null;
}

public record IndexSummary(
    int FileCount,
    int ReadErrorCount,
    int TotalLineCount,
    int TotalNonEmptyLineCount,
    int totalCodeItemCount,
    long TotalSizeBytes
);

