}

public class CodebaseIndexBuilder
{
    private readonly FileScanner _fileScanner;
    private readonly IndexSummaryBuilder _summaryBuilder;

    public CodebaseIndexBuilder(
        FileScanner fileScanner,
        IndexSummaryBuilder summaryBuilder)
    {
        _fileScanner = fileScanner;
        _summaryBuilder = summaryBuilder;
    }

    public CodebaseIndex Build(string rootPath, ScannerOptions scannerOptions)
    {
        List<FileIndexEntry> entries = _fileScanner.Scan(rootPath, scannerOptions);
        IndexSummary summary = _summaryBuilder.Build(entries);

        CodebaseIndex codebaseIndex = new CodebaseIndex(
            rootPath,
            DateTime.UtcNow,
            summary,
            entries
        );

        return codebaseIndex;
    }
}

public class CodeChunkBuilder
{
    public List<CodeChunk> Build(List<CodeItem> codeItems, string[] lines)
    {
        List<CodeChunk> codeChunks = new List<CodeChunk>();

        foreach (CodeItem codeItem in codeItems)
        {
            string text = GetTextRange(
                lines,
                codeItem.LineNumber,
                codeItem.EndLineNumber
            );

            CodeChunk codeChunk = new CodeChunk()
            {
                Kind = codeItem.Kind,
                Name = codeItem.Name,
                StartLineNumber = codeItem.LineNumber,
                EndLineNumber = codeItem.EndLineNumber,
                Text = text
            };

            codeChunks.Add(codeChunk);
        }

        return codeChunks;
    }

    private static string GetTextRange(string[] lines, int startLineNumber, int endLineNumber)
    {
        int startIndex = Math.Max(startLineNumber - 1, 0);
        int endIndex = Math.Min(endLineNumber - 1, lines.Length - 1);

        if (startIndex > endIndex)
        {
            return "";
        }

        List<string> selectedLines = new List<string>();

        for (int i = startIndex; i <= endIndex; i++)
        {
            selectedLines.Add(lines[i]);
        }

        return string.Join(Environment.NewLine, selectedLines);
    }
}

public class CodeItemExtractor
{
    public List<CodeItem> Extract(string extension, string[] lines)
    {
        List<CodeItem> codeItems = new List<CodeItem>();

        for (int i = 0; i < lines.Length; i++)
        {
            string trimmedLine = lines[i].Trim();

            if (string.IsNullOrWhiteSpace(trimmedLine))
            {
                continue;
            }

            if (trimmedLine.StartsWith("//"))
            {
                continue;
            }

            CodeItem? codeItem = null;

            if (extension == ".prg")
            {
                codeItem = TryCreateHarbourCodeItem(trimmedLine, i + 1);
            }

            if (extension == ".cs")
            {
                codeItem = TryCreateCSharpCodeItem(trimmedLine, i + 1);
            }

            if (codeItem is not null)
            {
                codeItems.Add(codeItem);
            }
        }

        return ApplyEndLineNumbers(codeItems, lines.Length);
    }

    private static CodeItem? TryCreateHarbourCodeItem(string line, int lineNumber)
    {
        if (line.StartsWith("class ", StringComparison.OrdinalIgnoreCase))
        {
            return CreateCodeItem(CodeItemKind.Class, line, lineNumber);
        }

        if (line.StartsWith("function ", StringComparison.OrdinalIgnoreCase))
        {
            return CreateCodeItem(CodeItemKind.Function, line, lineNumber);
        }

        if (line.StartsWith("procedure ", StringComparison.OrdinalIgnoreCase))
        {
            return CreateCodeItem(CodeItemKind.Procedure, line, lineNumber);
        }

        if (line.StartsWith("method ", StringComparison.OrdinalIgnoreCase))
        {
            return CreateCodeItem(CodeItemKind.Method, line, lineNumber);
        }

        return null;
    }

    private static CodeItem? TryCreateCSharpCodeItem(string line, int lineNumber)
    {
        string[] parts = SplitSignature(line);

        foreach (string part in parts)
        {
            if (part == "class")
            {
                return CreateCodeItem(CodeItemKind.Class, line, lineNumber);
            }

            if (part == "record")
            {
                return CreateCodeItem(CodeItemKind.Record, line, lineNumber);
            }

            if (part == "interface")
            {
                return CreateCodeItem(CodeItemKind.Interface, line, lineNumber);
            }
        }

        return null;
    }
    private static string[] SplitSignature(string signature)
    {
        char[] separators = [' ', '\t'];

        return signature.Split(
            separators,
            StringSplitOptions.RemoveEmptyEntries
        );
    }

    private static CodeItem CreateCodeItem(CodeItemKind kind, string signature, int lineNumber)
    {
        string name = ExtractNameFromSignature(kind, signature);

        CodeItem codeItem = new CodeItem()
        {
            Kind = kind,
            Name = name,
            LineNumber = lineNumber,
            EndLineNumber = lineNumber,
            Signature = signature
        };

        return codeItem;
    }

    private static string ExtractNameFromSignature(CodeItemKind kind, string signature)
    {
        string kindText = GetKindText(kind);
        string[] parts = SplitSignature(signature);

        for (int i = 0; i < parts.Length; i++)
        {
            if (!string.Equals(parts[i], kindText, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            int nameIndex = i + 1;

            if (kind == CodeItemKind.Record &&
                nameIndex < parts.Length &&
                (parts[nameIndex] == "class" || parts[nameIndex] == "struct"))
            {
                nameIndex++;
            }

            if (nameIndex >= parts.Length)
            {
                return "";
            }

            return CleanCodeItemName(parts[nameIndex]);
        }

        return "";
    }

    private static string GetKindText(CodeItemKind kind)
    {
        return kind switch
        {
            CodeItemKind.Class => "class",
            CodeItemKind.Record => "record",
            CodeItemKind.Interface => "interface",
            CodeItemKind.Function => "function",
            CodeItemKind.Procedure => "procedure",
            CodeItemKind.Method => "method",
            _ => ""
        };
    }

    private static string CleanCodeItemName(string name)
    {
        int parenthesisIndex = name.IndexOf('(');

        if (parenthesisIndex >= 0)
        {
            name = name[..parenthesisIndex];
        }

        int genericIndex = name.IndexOf('<');

        if (genericIndex >= 0)
        {
            name = name[..genericIndex];
        }

        return name.Trim('{', ':', ';');
    }
    private static List<CodeItem> ApplyEndLineNumbers(List<CodeItem> codeItems, int totalLineCount)
    {
        List<CodeItem> result = new List<CodeItem>();

        for (int i = 0; i < codeItems.Count; i++)
        {
            CodeItem currentCodeItem = codeItems[i];

            int endLineNumber = totalLineCount;

            if (i + 1 < codeItems.Count)
            {
                CodeItem nextCodeItem = codeItems[i + 1];
                endLineNumber = nextCodeItem.LineNumber - 1;
            }

            CodeItem updatedCodeItem = currentCodeItem with
            {
                EndLineNumber = endLineNumber
            };

            result.Add(updatedCodeItem);
        }

        return result;
    }
}

public class CommandLineOptionsParser
{
    public CommandLineOptions Parse(string[] args)
    {
        ValidateUnknownOptions(args);

        bool showHelp = HasHelpFlag(args);
        string rootPath = GetRootPath(args);

        CommandLineOptions options = new()
        {
            RootPath = rootPath,
            SearchOption = GetSearchOption(args),
            OutputPath = GetOutputPath(args, rootPath),
            ShowHelp = showHelp
        };

        return options;
    }

    private static void ValidateUnknownOptions(string[] args)
    {
        foreach (string arg in args)
        {
            if (!arg.StartsWith("--") && arg != "-h")
            {
                continue;
            }

            if (arg == "--top" ||
                arg == "--recursive" ||
                arg == "--output" ||
                arg == "--help" ||
                arg == "-h")
            {
                continue;
            }

            throw new ArgumentException($"Unknown option: {arg}");
        }
    }

    private static bool HasHelpFlag(string[] args)
    {
        foreach (string arg in args)
        {
            if (arg == "--help" || arg == "-h")
            {
                return true;
            }
        }

        return false;
    }

    private static string GetRootPath(string[] args)
    {
        if (args.Length > 0 && !args[0].StartsWith("--") && args[0] != "-h")
        {
            return args[0];
        }

        return Directory.GetCurrentDirectory();
    }

    private static SearchOption GetSearchOption(string[] args)
    {
        foreach (string arg in args)
        {
            if (arg == "--top")
            {
                return SearchOption.TopDirectoryOnly;
            }

            if (arg == "--recursive")
            {
                return SearchOption.AllDirectories;
            }
        }

        return SearchOption.AllDirectories;
    }

    private static string GetOutputPath(string[] args, string rootPath)
    {
        for (int i = 0; i < args.Length; i++)
        {
            if (args[i] != "--output")
            {
                continue;
            }

            int outputPathIndex = i + 1;

            if (outputPathIndex >= args.Length || args[outputPathIndex].StartsWith("--"))
            {
                throw new ArgumentException("Option --output requires a file path.");
            }

            string outputPath = args[outputPathIndex];

            if (!Path.GetExtension(outputPath).Equals(".json", StringComparison.OrdinalIgnoreCase))
            {
                throw new ArgumentException("Option --output must point to a .json file.");
            }

            return outputPath;
        }

        return Path.Combine(rootPath, "index.json");
    }
}

public class ConsoleIndexReporter
{
    public void Print(CodebaseIndex codebaseIndex)
    {
        foreach (FileIndexEntry entry in codebaseIndex.Files)
        {
            if (entry.IsReadSuccessfully)
            {
                Console.WriteLine($"{entry.RelativePath} | {entry.Extension} | {entry.LineCount} lines | {entry.CodeItemCount} code items | {entry.SizeBytes} bytes");
            }
            else
            {
                Console.WriteLine($"{entry.RelativePath} | READ ERROR | {entry.ErrorMessage}");
            }
        }

        Console.WriteLine();
        Console.WriteLine("Summary:");
        Console.WriteLine($"Files: {codebaseIndex.Summary.FileCount}");
        Console.WriteLine($"Lines: {codebaseIndex.Summary.TotalLineCount}");
        Console.WriteLine($"Non-empty lines: {codebaseIndex.Summary.TotalNonEmptyLineCount}");
        Console.WriteLine($"Code items: {codebaseIndex.Summary.totalCodeItemCount}");
        Console.WriteLine($"Size: {codebaseIndex.Summary.TotalSizeBytes} bytes");
        Console.WriteLine($"Read errors: {codebaseIndex.Summary.ReadErrorCount}");
    }
}

public class FileScanner
{
    private readonly CodeItemExtractor _codeItemExtractor;
    private readonly CodeChunkBuilder _codeChunkBuilder;
    public FileScanner(CodeItemExtractor codeItemExtractor, CodeChunkBuilder codeChunkBuilder)
    {
        _codeItemExtractor = codeItemExtractor;
        _codeChunkBuilder = codeChunkBuilder;
    }
    public List<FileIndexEntry> Scan(string rootPath, ScannerOptions options)
    {
        List<FileIndexEntry> entries = new List<FileIndexEntry>();

        List<string> filePaths = GetCandidateFiles(rootPath, options);

        foreach (string filePath in filePaths)
        {
            FileIndexEntry entry = CreateFileIndexEntry(rootPath, filePath);
            entries.Add(entry);
        }

        return entries;
    }

    private static List<string> GetCandidateFiles(string rootPath, ScannerOptions options)
    {
        List<string> filePaths = new List<string>();

        AddMatchingFilesFromDirectory(filePaths, rootPath, options.AllowedPatterns);

        if (options.SearchOption == SearchOption.TopDirectoryOnly)
        {
            return filePaths;
        }

        AddMatchingFilesFromSubdirectories(filePaths, rootPath, options);

        return filePaths;
    }
    private static void AddMatchingFilesFromDirectory(
    List<string> filePaths,
    string directoryPath,
    string[] allowedPatterns)
    {
        foreach (string pattern in allowedPatterns)
        {
            string[] matchedFiles = GetFilesSafe(directoryPath, pattern);
            filePaths.AddRange(matchedFiles);
        }
    }

    private static void AddMatchingFilesFromSubdirectories(
    List<string> filePaths,
    string directoryPath,
    ScannerOptions options)
    {
        string[] subdirectories = GetDirectoriesSafe(directoryPath);

        foreach (string subdirectory in subdirectories)
        {
            if (ShouldSkipDirectory(subdirectory, options.ExcludedDirectoryNames))
            {
                continue;
            }

            AddMatchingFilesFromDirectory(filePaths, subdirectory, options.AllowedPatterns);
            AddMatchingFilesFromSubdirectories(filePaths, subdirectory, options);
        }
    }
    private static string[] GetFilesSafe(string directoryPath, string pattern)
    {
        try
        {
            return Directory.GetFiles(
                directoryPath,
                pattern,
                SearchOption.TopDirectoryOnly
            );
        }
        catch
        {
            return [];
        }
    }

    private static string[] GetDirectoriesSafe(string directoryPath)
    {
        try
        {
            return Directory.GetDirectories(directoryPath);
        }
        catch
        {
            return [];
        }
    }
    private static bool ShouldSkipDirectory(string directoryPath, string[] excludedDirectoryNames)
    {
        string directoryName = Path.GetFileName(directoryPath);

        foreach (string excludedDirectoryName in excludedDirectoryNames)
        {
            if (string.Equals(directoryName, excludedDirectoryName, StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }
        }

        return false;
    }

    private FileIndexEntry CreateFileIndexEntry(string rootPath, string filePath)
    {
        FileInfo fileInfo = new FileInfo(filePath);

        string relativePath = Path.GetRelativePath(rootPath, filePath);
        string extension = fileInfo.Extension.ToLowerInvariant();

        try
        {
            string[] lines = File.ReadAllLines(filePath);

            int lineCount = lines.Length;
            int nonEmptyLineCount = CountNonEmptyLines(lines);
            List<CodeItem> codeItems = _codeItemExtractor.Extract(extension, lines);
            List<CodeChunk> codeChunks = _codeChunkBuilder.Build(codeItems, lines);

            FileIndexEntry entry = new FileIndexEntry()
            {
                FullPath = filePath,
                RelativePath = relativePath,
                Extension = extension,
                SizeBytes = fileInfo.Length,
                LineCount = lineCount,
                NonEmptyLineCount = nonEmptyLineCount,
                CodeItems = codeItems,
                CodeChunks = codeChunks,
                ErrorMessage = null
            };
            return entry;
        }
        catch (Exception exception)
        {
            FileIndexEntry entry = new FileIndexEntry()
            {
                FullPath = filePath,
                RelativePath = relativePath,
                Extension = extension,
                SizeBytes = fileInfo.Exists ? fileInfo.Length : 0,
                LineCount = 0,
                NonEmptyLineCount = 0,
                CodeItems = [],
                CodeChunks = [],
                ErrorMessage = exception.Message
            };
            return entry;
        }
    }

    private static int CountNonEmptyLines(string[] lines)
    {
        int count = 0;

        foreach (string line in lines)
        {
            if (!string.IsNullOrWhiteSpace(line))
            {
                count++;
            }
        }

        return count;
    }
}

