public class IndexJsonWriter
{
    public void Save(CodebaseIndex codebaseIndex, string outputPath)
    {
        JsonSerializerOptions jsonOptions = new JsonSerializerOptions()
        {
            WriteIndented = true
        };

        jsonOptions.Converters.Add(new JsonStringEnumConverter(JsonNamingPolicy.CamelCase));

        string? outputDirectoryPath = Path.GetDirectoryName(outputPath);

        if (!string.IsNullOrWhiteSpace(outputDirectoryPath))
        {
            Directory.CreateDirectory(outputDirectoryPath);
        }

        string json = JsonSerializer.Serialize(codebaseIndex, jsonOptions);

        File.WriteAllText(outputPath, json);

        Console.WriteLine($"Index saved to: {outputPath}");
    }
}

public class IndexSummaryBuilder
{
    public IndexSummary Build(List<FileIndexEntry> entries)
    {
        int readErrorCount = 0;
        int totalLineCount = 0;
        int totalNonEmptyLineCount = 0;
        int TotalCodeItemCount = 0;
        long totalSizeBytes = 0;

        foreach (FileIndexEntry entry in entries)
        {
            if (!entry.IsReadSuccessfully)
            {
                readErrorCount++;
            }

            totalLineCount += entry.LineCount;
            totalNonEmptyLineCount += entry.NonEmptyLineCount;
            TotalCodeItemCount += entry.CodeItemCount;
            totalSizeBytes += entry.SizeBytes;
        }

        IndexSummary summary = new IndexSummary(
            entries.Count,
            readErrorCount,
            totalLineCount,
            totalNonEmptyLineCount,
            TotalCodeItemCount,
            totalSizeBytes
        );

        return summary;
    }
}

public class CodeChunkBuilderTests
{
    [TestMethod]
    public void Build_ShouldCreateCodeChunkFromCodeItemRange()
    {
        CodeChunkBuilder builder = new CodeChunkBuilder();

        string[] lines =
        [
            "function GetPrice()",
            "    local nPrice := 10",
            "    return nPrice",
            "",
            "function Other()"
        ];

        List<CodeItem> codeItems =
        [
            new CodeItem()
            {
                Kind = CodeItemKind.Function,
                Name = "GetPrice",
                LineNumber = 1,
                EndLineNumber = 3,
                Signature = "function GetPrice()"
            }
        ];

        List<CodeChunk> codeChunks = builder.Build(codeItems, lines);

        Assert.HasCount(1, codeChunks);

        Assert.AreEqual(CodeItemKind.Function, codeChunks[0].Kind);
        Assert.AreEqual("GetPrice", codeChunks[0].Name);
        Assert.AreEqual(1, codeChunks[0].StartLineNumber);
        Assert.AreEqual(3, codeChunks[0].EndLineNumber);
        Assert.AreEqual(3, codeChunks[0].LineCount);

        string expectedText = string.Join(
            Environment.NewLine,
            [
                "function GetPrice()",
                "    local nPrice := 10",
                "    return nPrice"
            ]
        );

        Assert.AreEqual(expectedText, codeChunks[0].Text);
    }

    [TestMethod]
    public void Build_ShouldReturnEmptyListWhenCodeItemsAreEmpty()
    {
        CodeChunkBuilder builder = new CodeChunkBuilder();

        string[] lines =
        [
            "some text",
            "another text"
        ];

        List<CodeItem> codeItems = new List<CodeItem>();

        List<CodeChunk> codeChunks = builder.Build(codeItems, lines);

        Assert.HasCount(0, codeChunks);
    }
}

